#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int *alloc_ints(int n) {
    if (n <= 0) return NULL;
    int *arr = malloc((size_t)n * sizeof(int));
    if (arr) memset(arr, 0, (size_t)n * sizeof(int));
    return arr;
}

int *grow_ints(int *arr, int old_n, int new_n) {
    int *new_arr = realloc(arr, (size_t)new_n * sizeof(int));
    if (!new_arr) return NULL;
    if (new_n > old_n)
        memset(new_arr + old_n, 0, (size_t)(new_n - old_n) * sizeof(int));
    return new_arr;
}

void free_ints(int *arr) {
    free(arr);
}

validation.test_code:
void test_alloc_returns_non_null(void) {
    int *arr = alloc_ints(5);
    TEST_ASSERT_NOT_NULL(arr);
    free_ints(arr);
}

void test_alloc_zero_initialized(void) {
    int *arr = alloc_ints(4);
    TEST_ASSERT_NOT_NULL(arr);
    TEST_ASSERT_EQUAL_INT(0, arr[0]);
    TEST_ASSERT_EQUAL_INT(0, arr[3]);
    free_ints(arr);
}

void test_alloc_invalid(void) {
    TEST_ASSERT_NULL(alloc_ints(0));
    TEST_ASSERT_NULL(alloc_ints(-1));
}

void test_grow_preserves_data(void) {
    int *arr = alloc_ints(3);
    TEST_ASSERT_NOT_NULL(arr);
    arr[0] = 10; arr[1] = 20; arr[2] = 30;
    arr = grow_ints(arr, 3, 6);
    TEST_ASSERT_NOT_NULL(arr);
    TEST_ASSERT_EQUAL_INT(10, arr[0]);
    TEST_ASSERT_EQUAL_INT(20, arr[1]);
    TEST_ASSERT_EQUAL_INT(30, arr[2]);
    free_ints(arr);
}

void test_grow_new_cells_zero(void) {
    int *arr = alloc_ints(2);
    TEST_ASSERT_NOT_NULL(arr);
    arr[0] = 1; arr[1] = 2;
    arr = grow_ints(arr, 2, 5);
    TEST_ASSERT_NOT_NULL(arr);
    TEST_ASSERT_EQUAL_INT(0, arr[2]);
    TEST_ASSERT_EQUAL_INT(0, arr[3]);
    TEST_ASSERT_EQUAL_INT(0, arr[4]);
    free_ints(arr);
}

int main(void) {
    RUN_TEST(test_alloc_returns_non_null);
    RUN_TEST(test_alloc_zero_initialized);
    RUN_TEST(test_alloc_invalid);
    RUN_TEST(test_grow_preserves_data);
    RUN_TEST(test_grow_new_cells_zero);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}
